import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface BatchAuditRequest {
    campaign_id?: string;
    policy_id?: string;
    limit?: number;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { campaign_id, policy_id, limit = 50 } = await req.json() as BatchAuditRequest;

        // Get creatives to audit
        let query = supabase
            .from('creatives')
            .select('id')
            .eq('company_id', userData.company_id)
            .limit(limit);

        if (campaign_id) {
            query = query.eq('campaign_id', campaign_id);
        }

        const { data: creatives, error: creativesError } = await query;

        if (creativesError) {
            throw new Error('Failed to fetch creatives');
        }

        if (!creatives?.length) {
            return new Response(
                JSON.stringify({
                    success: true,
                    message: 'No creatives to audit',
                    audited: 0,
                }),
                {
                    headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                    status: 200,
                }
            );
        }

        // Call audit-creative for each creative
        const auditUrl = `${supabaseUrl}/functions/v1/audit-creative`;
        const results = {
            success: 0,
            failed: 0,
            errors: [] as string[],
        };

        for (const creative of creatives) {
            try {
                const response = await fetch(auditUrl, {
                    method: 'POST',
                    headers: {
                        'Authorization': authHeader,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        creative_id: creative.id,
                        policy_id,
                    }),
                });

                if (response.ok) {
                    results.success++;
                } else {
                    results.failed++;
                    const errorData = await response.json();
                    results.errors.push(`Creative ${creative.id}: ${errorData.error}`);
                }
            } catch (error) {
                results.failed++;
                results.errors.push(`Creative ${creative.id}: ${String(error)}`);
            }

            // Small delay to avoid rate limiting
            await new Promise(resolve => setTimeout(resolve, 100));
        }

        // Log batch audit
        await supabase.from('sync_history').insert({
            company_id: userData.company_id,
            sync_type: 'batch_audit',
            status: 'completed',
            records_synced: results.success,
            details: {
                total: creatives.length,
                success: results.success,
                failed: results.failed,
                campaign_id,
                policy_id,
            },
        });

        return new Response(
            JSON.stringify({
                success: true,
                total: creatives.length,
                audited: results.success,
                failed: results.failed,
                errors: results.errors.slice(0, 5), // Return first 5 errors only
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Batch audit error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AuditRequest {
    campaign_id: string;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const openaiApiKey = Deno.env.get('OPENAI_API_KEY');
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const { campaign_id } = await req.json() as AuditRequest;

        if (!campaign_id) throw new Error('Missing campaign_id');

        // Fetch Campaign Data
        const { data: campaign, error: campError } = await supabase
            .from('campaigns')
            .select(`
                *,
                ad_sets (*),
                creatives (*)
            `)
            .eq('id', campaign_id)
            .single();

        if (campError || !campaign) throw new Error('Campaign not found');

        // Fetch Metrics
        const { data: metrics } = await supabase
            .from('campaign_metrics')
            .select('*')
            .eq('campaign_id', campaign_id)
            .order('date', { ascending: false })
            .limit(30);

        // AI Analysis
        let aiAnalysis = null;
        let score = 70; // Default score

        if (openaiApiKey) {
            const prompt = `
                Você é um consultor sênior de Marketing Digital (Meta Ads).
                Analise esta campanha e forneça um diagnóstico estratégico.

                DADOS DA CAMPANHA:
                Nome: ${campaign.name}
                Objetivo: ${campaign.objective}
                Status: ${campaign.status}
                Orçamento: ${campaign.daily_budget ? 'Diário ' + campaign.daily_budget : 'Vitalício ' + campaign.lifetime_budget}

                PERFORMANCE (Últimos 30 dias):
                Total Gasto: ${metrics?.reduce((acc, m) => acc + m.spend, 0) || 0}
                Impressões: ${metrics?.reduce((acc, m) => acc + m.impressions, 0) || 0}
                Cliques: ${metrics?.reduce((acc, m) => acc + m.clicks, 0) || 0}
                Conversões: ${metrics?.reduce((acc, m) => acc + m.conversions, 0) || 0}

                ESTRUTURA:
                Qtd AdSets: ${campaign.ad_sets?.length || 0}
                Qtd Criativos: ${campaign.creatives?.length || 0}

                FORNEÇA EM JSON:
                1. quality_score (0-100)
                2. strengths (lista de pontos fortes)
                3. weaknesses (lista de pontos fracos/atenção)
                4. suggestions (lista de ações práticas para otimizar)
                5. tone_analysis (avaliação da estrutura)
            `;

            const response = await fetch('https://api.openai.com/v1/chat/completions', {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${openaiApiKey}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    model: 'gpt-4o-mini',
                    messages: [
                        { role: 'system', content: 'Responda apenas em JSON válido.' },
                        { role: 'user', content: prompt }
                    ],
                    temperature: 0.7,
                }),
            });

            const data = await response.json();
            const content = data.choices?.[0]?.message?.content;
            if (content) {
                try {
                    aiAnalysis = JSON.parse(content);
                    score = aiAnalysis.quality_score || score;
                } catch (e) {
                    console.error('JSON Parse Error', e);
                }
            }
        }

        // Save Audit
        const { data: audit, error: auditError } = await supabase
            .from('audits')
            .insert({
                company_id: campaign.company_id,
                campaign_id,
                status: 'completed',
                compliance_score: score,
                ai_analysis: aiAnalysis,
                issues: aiAnalysis?.weaknesses?.map((w: string) => ({ type: 'strategy', severity: 'warning', message: w })) || [],
                recommendations: aiAnalysis?.suggestions || [],
            })
            .select()
            .single();

        if (auditError) throw auditError;

        return new Response(JSON.stringify(audit), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 200,
        });

    } catch (error) {
        return new Response(JSON.stringify({ error: String(error) }), {
            headers: { ...corsHeaders, 'Content-Type': 'application/json' },
            status: 500,
        });
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface AuditRequest {
    creative_id: string;
    policy_id?: string;
}

interface AuditIssue {
    type: 'keyword' | 'text_length' | 'brand' | 'performance';
    severity: 'error' | 'warning' | 'info';
    message: string;
    details?: Record<string, unknown>;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const openaiApiKey = Deno.env.get('OPENAI_API_KEY');
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        const authHeader = req.headers.get('Authorization');
        if (!authHeader) {
            throw new Error('Missing authorization header');
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser(
            authHeader.replace('Bearer ', '')
        );
        if (authError || !user) {
            throw new Error('Unauthorized');
        }

        const { data: userData } = await supabase
            .from('users')
            .select('company_id')
            .eq('id', user.id)
            .single();

        if (!userData?.company_id) {
            throw new Error('User not associated with company');
        }

        const { creative_id, policy_id } = await req.json() as AuditRequest;

        if (!creative_id) {
            throw new Error('Missing creative_id');
        }

        // Get creative
        const { data: creative, error: creativeError } = await supabase
            .from('creatives')
            .select('*')
            .eq('id', creative_id)
            .eq('company_id', userData.company_id)
            .single();

        if (creativeError || !creative) {
            throw new Error('Creative not found');
        }

        // Get policy (use default if not specified)
        let policy;
        if (policy_id) {
            const { data } = await supabase
                .from('policies')
                .select('*')
                .eq('id', policy_id)
                .single();
            policy = data;
        } else {
            const { data } = await supabase
                .from('policies')
                .select('*')
                .eq('company_id', userData.company_id)
                .eq('is_default', true)
                .single();
            policy = data;
        }

        const issues: AuditIssue[] = [];
        const recommendations: string[] = [];
        let complianceScore = 100;
        let performanceScore = 100;

        // === Rule-based checks ===

        const creativeText = [creative.text, creative.headline, creative.description]
            .filter(Boolean)
            .join(' ')
            .toLowerCase();

        if (policy) {
            // Check prohibited keywords
            if (policy.prohibited_keywords?.length) {
                for (const keyword of policy.prohibited_keywords) {
                    if (creativeText.includes(keyword.toLowerCase())) {
                        issues.push({
                            type: 'keyword',
                            severity: 'error',
                            message: `Palavra proibida encontrada: "${keyword}"`,
                            details: { keyword },
                        });
                        complianceScore -= 15;
                    }
                }
            }

            // Check required keywords
            if (policy.required_keywords?.length) {
                for (const keyword of policy.required_keywords) {
                    if (!creativeText.includes(keyword.toLowerCase())) {
                        issues.push({
                            type: 'keyword',
                            severity: 'warning',
                            message: `Palavra obrigatória ausente: "${keyword}"`,
                            details: { keyword },
                        });
                        complianceScore -= 5;
                    }
                }
            }

            // Check text length
            const textLength = creativeText.length;
            if (policy.min_text_length && textLength < policy.min_text_length) {
                issues.push({
                    type: 'text_length',
                    severity: 'warning',
                    message: `Texto muito curto (${textLength} caracteres, mínimo: ${policy.min_text_length})`,
                    details: { current: textLength, min: policy.min_text_length },
                });
                complianceScore -= 10;
            }

            if (policy.max_text_length && textLength > policy.max_text_length) {
                issues.push({
                    type: 'text_length',
                    severity: 'warning',
                    message: `Texto muito longo (${textLength} caracteres, máximo: ${policy.max_text_length})`,
                    details: { current: textLength, max: policy.max_text_length },
                });
                complianceScore -= 10;
            }

            // Check performance metrics
            const ctr = Number(creative.ctr) || 0;
            const cpc = Number(creative.cpc) || 0;

            if (policy.ctr_min && ctr > 0 && ctr < policy.ctr_min) {
                issues.push({
                    type: 'performance',
                    severity: 'warning',
                    message: `CTR abaixo do mínimo (${ctr.toFixed(2)}% < ${policy.ctr_min}%)`,
                    details: { current: ctr, min: policy.ctr_min },
                });
                performanceScore -= 15;
                recommendations.push('Considere testar novas variações de copy para melhorar o CTR');
            }

            if (policy.cpc_max && cpc > 0 && cpc > policy.cpc_max) {
                issues.push({
                    type: 'performance',
                    severity: 'warning',
                    message: `CPC acima do máximo (R$${cpc.toFixed(2)} > R$${policy.cpc_max})`,
                    details: { current: cpc, max: policy.cpc_max },
                });
                performanceScore -= 15;
                recommendations.push('Revise a segmentação e o lance para reduzir o CPC');
            }
        }

        // === AI Analysis (if OpenAI key available) ===
        let aiAnalysis = null;

        if (openaiApiKey && creativeText.length > 10) {
            try {
                const openaiResponse = await fetch('https://api.openai.com/v1/chat/completions', {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${openaiApiKey}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        model: 'gpt-4o-mini',
                        messages: [
                            {
                                role: 'system',
                                content: `Você é um especialista em Políticas de Publicidade do Meta (Facebook/Instagram) e Copywriting Persuasivo.
Analise o anúncio abaixo com RIGOR.

1. VERIFICAÇÃO DE POLÍTICAS (Crucial):
- Identifique violações de "Saúde Pessoal" (antes/depois, zoom em partes do corpo).
- Promessas irrealistas ("Ganhe dinheiro rápido", "Perca 10kg em 1 dia").
- Linguagem ofensiva ou discriminatória.
- Categorias especiais não declaradas (Crédito, Emprego, Moradia, Temas Sociais).

2. ANÁLISE DE COPYWRITING:
- Avalie ganchos (Hooks).
- Clareza da oferta.
- Call to Action (CTA).

RETORNE JSON:
{
  "quality_score": (0-100),
  "policy_compliance_score": (0-100),
  "tone_analysis": "string",
  "strengths": ["string"],
  "weaknesses": ["string"],
  "policy_warnings": ["string"] (Lista de possíveis violações de política),
  "suggestions": ["string"] (Ações para melhorar performance e aprovação)
}`,
                            },
                            {
                                role: 'user',
                                content: `Analise este criativo:\n\nTexto Principal: ${creative.text || '(Vazio)'}\nHeadline: ${creative.headline || '(Vazio)'}\nDescrição: ${creative.description || '(Vazio)'}\nCTA: ${creative.call_to_action || '(Vazio)'}\nTipo: ${creative.creative_format || 'Imagem'}`,
                            },
                        ],
                        temperature: 0.7,
                        max_tokens: 500,
                    }),
                });

                if (openaiResponse.ok) {
                    const openaiData = await openaiResponse.json();
                    const content = openaiData.choices?.[0]?.message?.content;
                    if (content) {
                        try {
                            aiAnalysis = JSON.parse(content);

                            // Add AI recommendations
                            if (aiAnalysis.suggestions?.length) {
                                recommendations.push(...aiAnalysis.suggestions.slice(0, 3));
                            }
                        } catch {
                            console.log('Failed to parse AI response');
                        }
                    }
                }
            } catch (error) {
                console.error('AI analysis error:', error);
            }
        }

        // Clamp scores
        complianceScore = Math.max(0, Math.min(100, complianceScore));
        performanceScore = Math.max(0, Math.min(100, performanceScore));

        // Determine status
        const hasErrors = issues.some(i => i.severity === 'error');
        const status = hasErrors ? 'rejected' : (complianceScore >= 80 ? 'approved' : 'pending');

        // Save audit result
        const { data: audit, error: auditError } = await supabase
            .from('audits')
            .insert({
                company_id: userData.company_id,
                creative_id,
                policy_id: policy?.id || null,
                status,
                compliance_score: complianceScore,
                performance_score: performanceScore,
                issues,
                recommendations,
                ai_analysis: aiAnalysis,
            })
            .select()
            .single();

        if (auditError) {
            console.error('Audit save error:', auditError);
            throw new Error('Failed to save audit');
        }

        return new Response(
            JSON.stringify({
                success: true,
                audit_id: audit.id,
                status,
                compliance_score: complianceScore,
                performance_score: performanceScore,
                issues_count: issues.length,
                has_ai_analysis: !!aiAnalysis,
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Audit error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});

import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

interface CreativeFatigueResult {
    creative_id: string;
    creative_name: string;
    fatigue_level: 'low' | 'medium' | 'high' | 'critical';
    decline_percentage: number;
    days_active: number;
    recommendation: string;
}

serve(async (req) => {
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders });
    }

    try {
        const supabaseUrl = Deno.env.get('SUPABASE_URL')!;
        const supabaseServiceKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!;
        const supabase = createClient(supabaseUrl, supabaseServiceKey);

        // This function can be called via CRON or manually
        // Get all companies with active integrations
        const { data: integrations } = await supabase
            .from('integrations')
            .select('company_id')
            .eq('status', 'active')
            .eq('platform', 'meta_ads');

        if (!integrations?.length) {
            return new Response(
                JSON.stringify({ success: true, message: 'No active integrations' }),
                { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            );
        }

        const allResults: { company_id: string; fatigued_creatives: CreativeFatigueResult[] }[] = [];

        for (const integration of integrations) {
            const companyId = integration.company_id;

            // Get creatives with their metrics over time
            const thirtyDaysAgo = new Date();
            thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

            const { data: creatives } = await supabase
                .from('creatives')
                .select('id, name, created_at, impressions, clicks, ctr')
                .eq('company_id', companyId)
                .eq('status', 'active')
                .gt('impressions', 1000);

            if (!creatives?.length) continue;

            // Get historical metrics for comparison
            const { data: recentMetrics } = await supabase
                .from('creative_metrics')
                .select('creative_id, date, impressions, clicks, ctr')
                .eq('company_id', companyId)
                .gte('date', thirtyDaysAgo.toISOString().split('T')[0])
                .order('date', { ascending: true });

            const fatiguedCreatives: CreativeFatigueResult[] = [];

            for (const creative of creatives) {
                const creativeMetrics = recentMetrics?.filter(m => m.creative_id === creative.id) || [];

                if (creativeMetrics.length < 7) continue; // Need at least a week of data

                // Calculate CTR trend
                const firstWeekMetrics = creativeMetrics.slice(0, 7);
                const lastWeekMetrics = creativeMetrics.slice(-7);

                const avgFirstWeekCtr = firstWeekMetrics.reduce((acc, m) => acc + (m.ctr || 0), 0) / firstWeekMetrics.length;
                const avgLastWeekCtr = lastWeekMetrics.reduce((acc, m) => acc + (m.ctr || 0), 0) / lastWeekMetrics.length;

                if (avgFirstWeekCtr === 0) continue;

                const declinePercentage = ((avgFirstWeekCtr - avgLastWeekCtr) / avgFirstWeekCtr) * 100;
                const daysActive = Math.floor((Date.now() - new Date(creative.created_at).getTime()) / (1000 * 60 * 60 * 24));

                // Determine fatigue level
                let fatigueLevel: 'low' | 'medium' | 'high' | 'critical';
                let recommendation: string;

                if (declinePercentage >= 50) {
                    fatigueLevel = 'critical';
                    recommendation = 'Pausar imediatamente e substituir por novo criativo';
                } else if (declinePercentage >= 30) {
                    fatigueLevel = 'high';
                    recommendation = 'Preparar novo criativo para substituição em breve';
                } else if (declinePercentage >= 15) {
                    fatigueLevel = 'medium';
                    recommendation = 'Monitorar de perto e testar variações';
                } else {
                    fatigueLevel = 'low';
                    recommendation = 'Performance estável, continuar monitorando';
                }

                if (fatigueLevel !== 'low') {
                    fatiguedCreatives.push({
                        creative_id: creative.id,
                        creative_name: creative.name,
                        fatigue_level: fatigueLevel,
                        decline_percentage: Math.round(declinePercentage),
                        days_active: daysActive,
                        recommendation,
                    });

                    // Create notification for high/critical fatigue
                    if (fatigueLevel === 'high' || fatigueLevel === 'critical') {
                        await supabase.from('notifications').insert({
                            company_id: companyId,
                            type: 'creative_fatigue',
                            title: `Fadiga de Criativo: ${creative.name}`,
                            message: recommendation,
                            priority: fatigueLevel === 'critical' ? 'high' : 'medium',
                            metadata: {
                                creative_id: creative.id,
                                fatigue_level: fatigueLevel,
                                decline_percentage: Math.round(declinePercentage),
                            },
                        });
                    }
                }
            }

            if (fatiguedCreatives.length > 0) {
                allResults.push({
                    company_id: companyId,
                    fatigued_creatives: fatiguedCreatives,
                });
            }
        }

        return new Response(
            JSON.stringify({
                success: true,
                companies_analyzed: integrations.length,
                results: allResults,
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 200,
            }
        );

    } catch (error) {
        console.error('Creative fatigue detection error:', error);
        return new Response(
            JSON.stringify({
                success: false,
                error: String(error),
            }),
            {
                headers: { ...corsHeaders, 'Content-Type': 'application/json' },
                status: 400,
            }
        );
    }
});
